import boto3
import re

bedrock_agent = boto3.client('bedrock-agent-runtime')

def detect_kb_bias(agent_id, session_id, input_text, protected_attrs=['gender', 'race', 'age']):
    response = bedrock_agent.invoke_agent(
        agentId=agent_id,
        agentAliasId='latest',
        sessionId=session_id,
        inputText=input_text
    )

    chunks = response['completion'].split('SOURCES:')
    bias_scores = {}

    for attr in protected_attrs:
        attr_mentions = sum(1 for chunk in chunks if re.search(attr, chunk, re.IGNORECASE))
        bias_scores[attr] = attr_mentions / max(len(chunks), 1)

    return {
        'imbalanced_attrs': [attr for attr, score in bias_scores.items() if score > 0.3],
        'chunks_analyzed': len(chunks)
    }

