from collections import defaultdict

class BalancedRetriever:
    def __init__(self):
        self.metadata_index = defaultdict(list)

    def rebalance_chunks(self, chunks, target_groups=['male', 'female', 'non-binary']):
        group_chunks = defaultdict(list)

        for chunk in chunks:
            for group in target_groups:
                if group in chunk.lower():
                    group_chunks[group].append(chunk)
                    break

        balanced = []
        for group in target_groups:
            if group_chunks[group]:
                balanced.append(group_chunks[group][0])

        return balanced[:3]  # Return top 3 balanced chunks

