import json

def lambda_handler(event, context):
    candidates = event['candidates']

    # Original scoring
    for candidate in candidates:
        candidate['raw_score'] = candidate['experience'] * 0.6 + candidate['skills'] * 0.4

    # Fairness adjustment
    demo_groups = defaultdict(list)
    for c in candidates:
        demo = c.get('demographic', 'unknown')
        demo_groups[demo].append(c)

    group_avgs = {group: sum(c['raw_score'] for c in group) / len(group) 
                  for group in demo_groups.values()}
    global_avg = sum(group_avgs.values()) / len(group_avgs)

    for candidate in candidates:
        demo = candidate.get('demographic', 'unknown')
        fairness_adjust = (global_avg - group_avgs[demo]) * 0.1
        candidate['adjusted_score'] = candidate['raw_score'] + fairness_adjust

    return {
        'candidates': candidates,
        'fairness_applied': True
    }
